Generate:
- hook
- lead_in
- main_headline
- subheading
- body_copy

options.systemMessage:
=You are a marketing copywriter for QuoHR.
QuoHR provides HR management solutions that improve productivity and efficiency.
Your task is to generate marketing banner text using standard text hierarchy.
Use simple English.
Create short, clear lines for each text role.
Do not add explanations.
Output only structured JSON.
{
  "hook": {
    "type": "string"
  },
  "lead_in": {
    "type": "string"
  },
  "main_headline": {
    "type": "string"
  },
  "subheading": {
    "type": "string"
  },
  "body_copy": {
    "type": "string"
  }
}

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "hook": {
      "type": "string",
      "description": "Attention-grabbing opening line",
      "minLength": 1
    },
    "lead_in": {
      "type": "string",
      "description": "Short line leading to main headline",
      "minLength": 1
    },
    "main_headline": {
      "type": "string",
      "description": "Primary bold message on the banner",
      "minLength": 1
    },
    "subheading": {
      "type": "string",
      "description": "Secondary text supporting the main headline",
      "minLength": 1
    },
    "body_copy": {
      "type": "string",
      "description": "Brief description or benefit statement",
      "minLength": 1
    }
  },
  "required": ["hook", "lead_in", "main_headline", "subheading", "body_copy"]
}

parameters.jsCode:
